/**
 * Returns per-gram nutrition for a named food item using a 3-tier lookup cascade:
1. **recipe_db** (source="recipe_db"): exact match from the seeded recipe database (58,711-row source CSV, filtered to complete-nutrition entries) — most accurate
2. **icmr_nin** (source="icmr_nin"): ICMR-NIN 2024 food composition table — authoritative reference
3. **generic_estimate** (source="generic_estimate"): Gemini AI estimate — use only as fallback
Use this endpoint for nutrition logging and display. Do NOT use /nutrition/analyze macro estimates
for per-food display as those are heuristic approximations for scoring purposes only.

 * @summary Authoritative 3-tier nutrition lookup: recipe DB → ICMR NIN → generic estimate
 */
export const LookupNutritionQueryParams = zod.object({
  q: zod.coerce.string().describe('Food name (e.g. \"dal makhani\")'),
  grams: zod.coerce.number().describe("Serving weight in grams"),
});

export const LookupNutritionResponse = zod.object({
  query: zod.string(),
  grams: zod.number(),
  calories: zod.number(),
  protein: zod.number(),
  carbs: zod.number().optional(),
  fat: zod.number().optional(),
  fiber: zod.number().optional(),
  iron: zod.number().optional(),
  calcium: zod.number().optional(),
  source: zod.enum(["recipe_db", "icmr_nin", "generic_estimate"]),
});

